+				hdr, err := tar.FileInfoHeader(info, "")
+				if err != nil {
+					return err
+				}
+				hdr.Uid, hdr.Gid = 0, 0
+				orig, ok := seen[di]
+				if ok {
+					hdr.Typeflag = tar.TypeLink
+					hdr.Linkname = orig
+					hdr.Size = 0
+					hdr.Name = filename
+					return tw.WriteHeader(hdr)
+				}
+				f, err := os.Open(filename)
+				if err != nil {
