+				}
+
+				hdr.Name = filename
+				if err := tw.WriteHeader(hdr); err != nil {
+					f.Close()
+					return err
+				}
+
+				_, err = io.Copy(tw, f)
+				f.Close()
+				if err == nil && isHardLink {
+					seen[di] = filename
+				}
+				return err
+			}
+
